// alien.js — Bridge alien screen sprite (helmsman1/captain pattern)
window.createAlien = function(bridgeRoomGroup, extraEditables) {
  const BRIDGE_ROOM_R = window.BRIDGE_ROOM_R || 280;
  const _img = new Image();
  _img.onload = function() {
    const tex = new THREE.Texture(_img);
    tex.needsUpdate = true;
    const spriteH = 100;
    const aspect = 1;
    const alienPlane = new THREE.Mesh(
      new THREE.PlaneGeometry(spriteH * aspect, spriteH),
      new THREE.MeshBasicMaterial({
        map: tex,
        transparent: true,
        alphaTest: 0.1,
        side: THREE.DoubleSide,
        depthWrite: false
      })
    );
    alienPlane.name = 'bridge_alien_screen';
    alienPlane.userData.isEditable = true;
    alienPlane.userData.spriteType = 'alien_screen';
    alienPlane.position.set(0, spriteH / 2 + 40, -BRIDGE_ROOM_R + 30);
    alienPlane.rotation.y = 0;
    alienPlane.visible = false;
    bridgeRoomGroup.add(alienPlane);
    extraEditables.push(alienPlane);

    const mouthCanvas = document.createElement('canvas');
    mouthCanvas.width = 64; mouthCanvas.height = 32;
    const mouthCtx = mouthCanvas.getContext('2d');
    const mouthTex = new THREE.CanvasTexture(mouthCanvas);
    const mouthPlane = new THREE.Mesh(
      new THREE.PlaneGeometry(spriteH * aspect * 0.1644, spriteH * 0.0580),
      new THREE.MeshBasicMaterial({
        map: mouthTex,
        transparent: true,
        depthWrite: false,
        side: THREE.DoubleSide
      })
    );
    mouthPlane.position.set(
      (0.4855 - 0.5) * spriteH * aspect,
      (0.5 - 0.5180) * spriteH,
      1
    );
    alienPlane.add(mouthPlane);
    let _mouthFrame = 0;
    let _mouthInterval = null;
    function _drawMouth(amplitude) {
      const w = mouthCanvas.width;
      const h = mouthCanvas.height;
      mouthCtx.clearRect(0, 0, w, h);
      if (amplitude < 0.15) return;
      const openH = Math.round(h * amplitude * 1.200);
      const openW = Math.round(w * 0.900);
      const x = Math.round((w - openW) / 2);
      const y = Math.round((h - openH) / 2);
      mouthCtx.fillStyle = '#2a2a2a';
      const r = Math.min(openH * 0.120, openW / 2, openH / 2);
      mouthCtx.beginPath();
      mouthCtx.roundRect(x, y, openW, openH, r);
      mouthCtx.fill();
      mouthTex.needsUpdate = true;
    }
    window.alienMouthStart = function() {
      _mouthFrame = 0;
      if (_mouthInterval) clearInterval(_mouthInterval);
      _mouthInterval = setInterval(function() {
        const data = window.ALIEN_MOUTH_DATA;
        if (!data) return;
        const amp = data[_mouthFrame % data.length];
        _drawMouth(amp);
        _mouthFrame++;
      }, 33);
    };
    window.alienMouthStop = function() {
      if (_mouthInterval) { clearInterval(_mouthInterval); _mouthInterval = null; }
      mouthCtx.clearRect(0, 0, mouthCanvas.width, mouthCanvas.height);
      mouthTex.needsUpdate = true;
    };
    console.log('✅ bridge_alien_screen added to scene', alienPlane);
  };
  const dataURL = "data:image/jpeg;base64,";
  _img.src = dataURL;
};
